import 'dart:io';

import 'package:flutter/material.dart';
import 'package:intl/intl.dart';
import 'package:provider/provider.dart';

import '../../providers/auth_provider.dart';
import '../../services/offline_transaction_sync_service.dart';
import 'sync_audit_screen.dart';

enum SyncQueueFilter { all, pending, failed, conflict }

class SyncQueueScreen extends StatefulWidget { const SyncQueueScreen({super.key}); @override State<SyncQueueScreen> createState()=>_SyncQueueScreenState(); }

class _SyncQueueScreenState extends State<SyncQueueScreen> {
  final _sync=OfflineTransactionSyncService.instance; final Set<String> _selected=<String>{}; SyncQueueFilter _filter=SyncQueueFilter.all; bool _busy=false;
  @override void initState(){super.initState(); _sync.addListener(_on);}
  @override void dispose(){_sync.removeListener(_on); super.dispose();}
  void _on(){ if(!mounted) return; setState(()=>_selected.removeWhere((id)=>!_sync.queue.any((q)=>q.clientTransactionId==id))); }
  SyncActionActor _actor(AuthProvider a)=>SyncActionActor(userId:a.appUser?.id??'unknown',role:a.appUser?.role??'unknown',device:'${Platform.operatingSystem}-${Platform.localHostname}');
  Future<void> _run(Future<void> Function() action,{String? ok}) async { if(_busy) return; setState(()=>_busy=true); try{await action(); if(mounted&&ok!=null) ScaffoldMessenger.of(context).showSnackBar(SnackBar(content: Text(ok)));} catch(e){ if(mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(content: Text('Action failed: $e')));} finally{ if(mounted) setState(()=>_busy=false);} }
  @override Widget build(BuildContext context){ final auth=context.watch<AuthProvider>(); final role=auth.appUser?.role??'unknown'; final isCashier=role=='cashier',isManager=role=='manager',isAdmin=role=='admin'; final canViewLogs=isAdmin; final queue=_filtered(_sync.queue); return Scaffold(backgroundColor: const Color(0xFF0D1117),appBar: AppBar(backgroundColor: const Color(0xFF161B22),title: Text('Sync Queue (${role.toUpperCase()})'),actions:[if(canViewLogs) IconButton(icon: const Icon(Icons.fact_check_outlined),onPressed: ()=>Navigator.push(context,MaterialPageRoute(builder:(_)=>const SyncAuditScreen()))),IconButton(icon: const Icon(Icons.sync),onPressed:(_busy||isCashier)?null:()=>_run(()=>_sync.forceSyncNow(actor:_actor(auth)),ok:'Forced sync started'))]),body: Column(children:[_filters(),Padding(padding: const EdgeInsets.all(8),child: Wrap(spacing:8,runSpacing:8,children:[ElevatedButton.icon(onPressed:(_busy||_selected.isEmpty)?null:()=>_run(()=>_sync.retrySelected(_selected.toList(),actor:_actor(auth)),ok:'Retry requested'),icon: const Icon(Icons.replay_outlined),label: const Text('Retry selected')),OutlinedButton.icon(onPressed:(_busy||(!isManager&&!isAdmin))?null:()=>_run(()=>_sync.retryAllFailed(actor:_actor(auth)),ok:'Retried failed items'),icon: const Icon(Icons.restart_alt),label: const Text('Retry all failed')),OutlinedButton.icon(onPressed:(_busy||_selected.length!=1||(!isManager&&!isAdmin))?null:()=>_run(()=>_sync.acknowledgeConflict(clientTransactionId:_selected.first,actor:_actor(auth)),ok:'Conflict acknowledged'),icon: const Icon(Icons.rule),label: const Text('Acknowledge conflict')),OutlinedButton.icon(onPressed:(_busy||_selected.length!=1||(!isManager&&!isAdmin))?null:()=>_run(()=>_sync.deleteCorruptedItem(clientTransactionId:_selected.first,actor:_actor(auth)),ok:'Queue item deleted'),icon: const Icon(Icons.delete_outline),label: const Text('Delete corrupted'))])),Expanded(child: queue.isEmpty?const Center(child:Text('No queued transactions for current filter.',style: TextStyle(color: Colors.white60))):ListView.separated(padding: const EdgeInsets.fromLTRB(12,8,12,16),itemCount: queue.length,separatorBuilder:(_,__)=>const SizedBox(height:8),itemBuilder:(_,i){final tx=queue[i]; final selected=_selected.contains(tx.clientTransactionId); final canSelect=!isCashier||(tx.cashierId==auth.appUser?.id&&tx.state==OfflineSyncState.failed); return InkWell(onTap: ()=>_details(tx),child: Container(padding: const EdgeInsets.all(10),decoration: BoxDecoration(color: const Color(0xFF161B22),borderRadius: BorderRadius.circular(12),border: Border.all(color:selected?const Color(0xFFE8B84B):Colors.white10)),child: Row(children:[Checkbox(value:selected,onChanged:!canSelect?null:(v)=>setState((){if(v==true){_selected.add(tx.clientTransactionId);}else{_selected.remove(tx.clientTransactionId);}})),Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start,children:[Text(tx.clientTransactionId,maxLines:1,overflow: TextOverflow.ellipsis,style: const TextStyle(color: Colors.white,fontWeight: FontWeight.w600)),const SizedBox(height:6),Wrap(spacing:10,runSpacing:6,children:[_status(tx.state),Text('Age: ${_age(DateTime.now().difference(tx.createdAt))}',style: const TextStyle(color: Colors.white70,fontSize: 12)),Text('Retries: ${tx.retryCount}',style: const TextStyle(color: Colors.white70,fontSize: 12)),Text('Needs review: ${tx.requiresManagerReview ? 'Yes' : 'No'}',style: const TextStyle(color: Colors.white70,fontSize: 12))])])),const Icon(Icons.chevron_right,color: Colors.white38)])));})),Container(width: double.infinity,padding: const EdgeInsets.fromLTRB(12,8,12,12),decoration: BoxDecoration(color: const Color(0xFF11161D),border: Border(top: BorderSide(color: Colors.white.withValues(alpha: 0.08)))),child: _sync.auditLogs.isEmpty?const Text('No local action logs yet.',style: TextStyle(color: Colors.white54,fontSize: 12)):Column(crossAxisAlignment: CrossAxisAlignment.start,children:_sync.auditLogs.take(4).map((l){final t=DateFormat('HH:mm:ss').format(l.timestamp.toLocal()); return Padding(padding: const EdgeInsets.only(bottom: 4),child: Text('[$t] ${l.action} · ${l.result} · ${l.role}',style: const TextStyle(color: Colors.white60,fontSize: 12)));}).toList()))])); }
  Widget _filters()=>Padding(padding: const EdgeInsets.fromLTRB(12,12,12,4),child: Wrap(spacing:8,children:[_chip('All',SyncQueueFilter.all),_chip('Pending',SyncQueueFilter.pending),_chip('Failed',SyncQueueFilter.failed),_chip('Conflict',SyncQueueFilter.conflict)]));
  Widget _chip(String l,SyncQueueFilter f){final s=_filter==f; return ChoiceChip(label: Text(l),selected:s,onSelected:(_)=>setState(()=>_filter=f),labelStyle: TextStyle(color:s?Colors.black:Colors.white70),backgroundColor: const Color(0xFF161B22),selectedColor: const Color(0xFFE8B84B));}
  Widget _status(OfflineSyncState s){final l=s==OfflineSyncState.syncing?'pending':s.name; final c=s==OfflineSyncState.pending?const Color(0xFFE8B84B):s==OfflineSyncState.syncing?const Color(0xFF3498DB):s==OfflineSyncState.synced?const Color(0xFF2ECC71):s==OfflineSyncState.failed?const Color(0xFFE74C3C):const Color(0xFF9B59B6); return Container(padding: const EdgeInsets.symmetric(horizontal: 8,vertical: 3),decoration: BoxDecoration(color:c.withValues(alpha: 0.15),borderRadius: BorderRadius.circular(999)),child: Text(l.toUpperCase(),style: TextStyle(color:c,fontWeight: FontWeight.w700,fontSize: 11)));}
  List<QueuedOfflineTransaction> _filtered(List<QueuedOfflineTransaction> q)=>q.where((tx)=>switch(_filter){SyncQueueFilter.all=>true,SyncQueueFilter.pending=>tx.state==OfflineSyncState.pending||tx.state==OfflineSyncState.syncing,SyncQueueFilter.failed=>tx.state==OfflineSyncState.failed,SyncQueueFilter.conflict=>tx.state==OfflineSyncState.conflict}).toList()..sort((a,b)=>b.createdAt.compareTo(a.createdAt));
  Future<void> _details(QueuedOfflineTransaction tx) async=>showModalBottomSheet<void>(context: context,backgroundColor: const Color(0xFF161B22),builder:(_)=>SafeArea(child: Padding(padding: const EdgeInsets.all(16),child: Column(mainAxisSize: MainAxisSize.min,crossAxisAlignment: CrossAxisAlignment.start,children:[const Text('Transaction details',style: TextStyle(color: Colors.white,fontWeight: FontWeight.bold,fontSize: 18)),const SizedBox(height:12),Text('ID: ${tx.clientTransactionId}',style: const TextStyle(color: Colors.white70)),Text('Status: ${tx.state.name}',style: const TextStyle(color: Colors.white70)),Text('Retry count: ${tx.retryCount}',style: const TextStyle(color: Colors.white70)),if(tx.lastError!=null) Text('Last error: ${tx.lastError}',style: const TextStyle(color: Colors.white70)),if(tx.conflictType!=null) Text('Conflict type: ${tx.conflictType}',style: const TextStyle(color: Colors.white70))]))));
  String _age(Duration d)=>d.inHours>=1?'${d.inHours}h ${d.inMinutes%60}m':d.inMinutes>=1?'${d.inMinutes}m':'${d.inSeconds}s';
}
